func (h *handler) CreatePlan() CreatePlanHandler {
  return httptransport.NewHandler(
    func(ctx context.Context, r *http.Request) (CreatePlanRequest, error) {
      body := api.PlanCreate{}
      if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil { return CreatePlanRequest{}, err }
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return CreatePlanRequest{}, err }
      req, err := AsCreatePlanRequest(body, ns)
      // ... isCreditsEnabled guard, set IgnoreNonCriticalIssues ...
      return req, err
    },
    func(ctx context.Context, request CreatePlanRequest) (CreatePlanResponse, error) {
      p, err := h.service.CreatePlan(ctx, request)
      if err != nil { return CreatePlanResponse{}, err }
      return FromPlan(*p)
    },
    commonhttp.JSONResponseEncoderWithStatus[CreatePlanResponse](http.StatusCreated),
    httptransport.AppendOptions(h.options, httptransport.WithOperationName("createPlan"), httptransport.WithErrorEncoder(productcataloghttp.ValidationErrorEncoder(productcataloghttp.ResourceKindPlan)))...,
  )
}

func (s service) CreatePlan(ctx context.Context, params plan.CreatePlanInput) (*plan.Plan, error) {
  fn := func(ctx context.Context) (*plan.Plan, error) {
    if err := params.Validate(); err != nil { return nil, err }
    // enforce single-draft-per-key + version auto-increment via ListPlans
    for idx := range params.Phases {
      if err := featureresolver.ResolveFeaturesForRateCards(ctx, s.featureResolver, params.Namespace, &params.Phases[idx].RateCards); err != nil { return nil, err }
      if err := s.resolveTaxCodes(ctx, params.Namespace, &params.Phases[idx].RateCards); err != nil { return nil, err }
    }
    p, err := s.adapter.CreatePlan(ctx, params)
    if err != nil { return nil, err }
    if err := s.publisher.Publish(ctx, plan.NewPlanCreateEvent(ctx, p)); err != nil { return nil, err }
    return p, nil
  }
  return transaction.Run(ctx, s.adapter, fn)
}
